def in_box(lo, hi, x):
    return all(lo[i] <= x[i] <= hi[i]
              for i in range(len(x)))

def quad_form(Q, x):
    n = len(x)
    return sum(x[i]*Q[i][j]*x[j]
              for i in range(n) for j in range(n))

def lqr_gain_scalar(a, b, q, r):
    P = q
    for _ in range(1000):
        Pn = q + a*a*P - (a*P*b)**2/(r + b*b*P)
        if abs(Pn - P) < 1e-12:
            P = Pn; break
        P = Pn
    return (b*P*a)/(r + b*b*P)

