ch02.solution:
def stage_cost(Q, R, x, u):
    def qf(M, v):
        n = len(v)
        return sum(v[i]*M[i][j]*v[j]
                  for i in range(n) for j in range(n))
    return qf(Q, x) + qf(R, u)

def traj_cost(xs, us, q, r, pf):
    j = sum(q*x*x for x in xs[:-1]) + sum(r*u*u for u in us)
    return j + pf*xs[-1]*xs[-1]

def is_posdef2(Q):
    det = Q[0][0]*Q[1][1] - Q[0][1]*Q[1][0]
    return Q[0][0] > 0 and det > 0

def in_terminal_set(P, x, c):
    qf = sum(x[i]*P[i][j]*x[j]
            for i in range(len(x)) for j in range(len(x)))
    return qf <= c + 1e-9

