ch04.solution:
def kalman_update(xpred, ppred, y, h, r):
    K = ppred*h/(h*h*ppred + r)
    return [xpred + K*(y - h*xpred), (1 - K*h)*ppred]

def kf_steady_variance(a, h, q, r):
    p = q
    for _ in range(1000):
        ppred = a*a*p + q
        pn = ppred - ppred*ppred*h*h/(h*h*ppred + r)
        if abs(pn - p) < 1e-13:
            p = pn; break
        p = pn
    return p

