ch06.solution:
def gauss_seidel_step(A, b, x):
    xn = list(x); n = len(b)
    for i in range(n):
        xn[i] = (b[i] - sum(A[i][j]*xn[j]
                for j in range(n) if j != i))/A[i][i]
    return xn

def convex_combine(xold, xnew, w):
    return [(1 - w)*xold[i] + w*xnew[i]
            for i in range(len(xold))]

def cooperative_cost(costs, weights):
    return sum(costs[i]*weights[i]
              for i in range(len(costs)))

def consensus_step(vals, i, neighbors):
    grp = [vals[i]] + [vals[j] for j in neighbors]
    return sum(grp)/len(grp)

def coupled_dynamics(A, x):
    n = len(x)
    return [sum(A[i][j]*x[j] for j in range(n))
            for i in range(n)]

ch07.solution:
def find_region(bounds, x):
    for i, (lo, hi) in enumerate(bounds):
        if lo <= x < hi:
            return i
    return -1

def qp_scalar(q, c, umin, umax):
    u = -c/q
    return max(umin, min(umax, u))

def explicit_lqr(k, x, umin, umax):
    u = -k*x
    return max(umin, min(umax, u))

def eval_pwa(regions, x):
    for lo, hi, gain, off in regions:
        if lo <= x < hi:
            return gain*x + off
    return None

def eval_pwq(regions, x):
    for lo, hi, a, b, c in regions:
        if lo <= x < hi:
            return a*x*x + b*x + c
    return None

def in_region(H, g, x):
    return all(sum(H[i][j]*x[j] for j in range(len(x)))
              <= g[i] + 1e-9 for i in range(len(g)))

ch08.solution:
def rk2_step(x, a, dt):
    k1 = a*x
    return x + dt*a*(x + dt/2*k1)

def newton_sqrt(s, n):
    x = s if s > 0 else 1.0
    for _ in range(n):
        x = 0.5*(x + s/x)
    return x

def single_shooting(x0, us, a, b, dt):
    x = x0
    for u in us:
        x = x + dt*(a*x + b*u)
    return x

def normal_matrix(J):
    return [[J[i]*J[j] for j in range(len(J))]
            for i in range(len(J))]
